// Map each selected catalog_line (sent by the app in the webhook body) to the
// Hermes item shape. Hermes inserts by EAN: a NEW ean is created, an EXISTING
// ean is ignored (no update, no duplicate) — so we just send everything selected.
// Field mapping is the confirmed one.
const lines = $('Webhook').first().json.body?.lines ?? [];
return lines.map(l => ({ json: {
  _line_id: l.id,
  _ean: l.ean ?? null,
  item: {
    title: l.title ?? null,
    author: l.artist ?? null,
    releaseDate: l.release_date ?? null,
    format: l.format ?? null,
    ean: l.ean ?? null,
    calculationGroup: l.calculation_group ?? null,
    supplierCode: l.supplier_code ?? null,
  },
} }));

// Collect all lines into a single { items:[...] } batch for one POST, keeping a
// parallel meta list so we can mark the right lines as sent afterwards.
const all = $input.all();
return [{ json: {
  items: all.map(i => i.json.item),
  meta: all.map(i => ({ line_id: i.json._line_id, ean: i.json._ean })),
} }];

// One row per submitted line so we can mark it sent in Supabase. We DON'T rely
// on Hermes returning an id (it dedups by EAN and doesn't update); our own
// sent_at/status is the record that this EAN was pushed.
// TODO (live call): if the POST response returns a per-item otherId/item_code,
// capture it here into hermes_id. Response shape unconfirmed until the first real send.
const meta = $('Aggregate').first().json.meta;
return meta.map(m => ({ json: { id: m.line_id } }));
